double calculateArea(double ax, double ay, double bx, double by, double cx, double cy) {
    double side1 = sqrt((bx - ax) * (bx - ax) + (by - ay) * (by - ay));
    double side2 = sqrt((cx - bx) * (cx - bx) + (cy - by) * (cy - by));
    double side3 = sqrt((ax - cx) * (ax - cx) + (ay - cy) * (ay - cy));

    double s = (side1 + side2 + side3) / 2.0;
    return sqrt(s * (s - side1) * (s - side2) * (s - side3));
}

